/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../input/BTInputClear.css';

/*
 * BTInputFieldUnit — split input: unit dropdown (left) + text field (right).
 * Each panel owns its own independent border.
 * Left border activates when the unit dropdown opens.
 * Right border activates when the text field is focused.
 *
 * Shared by Vue (BTInputFieldUnit.vue) and React (BTInputFieldUnit.tsx).
 * Figma node 702-3937.
 */

.bt-input-field-unit__wrapper {
  display: flex;
  flex-direction: column;
  font-family: var(--typography-font-family-sans);
}

/* Flex row — 4px gap between the two independent panels (Figma spacing.xs) */
.bt-input-field-unit__row {
  display: flex;
  align-items: stretch;
  gap: var(--space-xs);
  min-height: 48px;
}

/* ── Left panel ─────────────────────────────────────────────────────── */
.bt-input-field-unit__left {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0 var(--space-sm);
  width: max-content;
  min-width: 72px;
  flex-shrink: 0;
  cursor: pointer;
  position: relative;
  user-select: none;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__left--active   { border-color: var(--color-brand-primary); }
.bt-input-field-unit__left--error    { border-color: var(--text-error); }
.bt-input-field-unit__left--disabled { background: var(--bg-subtle); cursor: not-allowed; }

/* ── Right panel ────────────────────────────────────────────────────── */
.bt-input-field-unit__right {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 8px 12px;
  position: relative;
  min-width: 0;
  overflow: hidden;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__right--active   { border-color: var(--color-brand-primary); }
.bt-input-field-unit__right--error    { border-color: var(--text-error); }
.bt-input-field-unit__right--disabled { background: var(--bg-subtle); }

.bt-input-field-unit__right-inner {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

/* ── Unit label (top of left panel) ────────────────────────────────── */
.bt-input-field-unit__unit-label {
  font-size: var(--typography-font-size-2xs);
  font-weight: 600;
  line-height: 1;
  color: var(--text-secondary);
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__left--active   .bt-input-field-unit__unit-label { color: var(--color-brand-primary); }
.bt-input-field-unit__left--error    .bt-input-field-unit__unit-label { color: var(--text-error); }
.bt-input-field-unit__left--disabled .bt-input-field-unit__unit-label { color: var(--text-disabled); }

/* ── Unit value row ─────────────────────────────────────────────────── */
.bt-input-field-unit__unit-row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}
.bt-input-field-unit__unit-value {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  white-space: nowrap;
}
.bt-input-field-unit__left--disabled .bt-input-field-unit__unit-value { color: var(--text-disabled); }

.bt-input-field-unit__unit-chevron {
  display: flex;
  align-items: center;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  color: var(--text-secondary);
  flex-shrink: 0;
}
.bt-input-field-unit__unit-chevron:disabled { color: var(--text-disabled); cursor: not-allowed; }
.bt-input-field-unit__unit-chevron svg {
  width: 16px;
  height: 16px;
  fill: currentColor;
  transition: transform 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__unit-chevron--open svg { transform: rotate(180deg); }

/* ── Field floating label ───────────────────────────────────────────── */
.bt-input-field-unit__field-label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-md);
  inset-inline-end: var(--space-sm);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: top 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-weight 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
  /* RTL: text aligns inline-start (right in RTL) automatically via text-align */
  text-align: start;
}
.bt-input-field-unit__field-label--floating {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-2xs);
  font-weight: 600;
}
.bt-input-field-unit__right--active   .bt-input-field-unit__field-label { color: var(--color-brand-primary); }
.bt-input-field-unit__right--error    .bt-input-field-unit__field-label { color: var(--text-error); }
.bt-input-field-unit__right--disabled .bt-input-field-unit__field-label { color: var(--text-disabled); }

/* ── Text input ─────────────────────────────────────────────────────── */
.bt-input-field-unit__field {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  padding: 0;
  min-width: 0;
}
.bt-input-field-unit__field--has-label { padding-top: 12px; }
.bt-input-field-unit__field::placeholder { color: var(--text-secondary); font-weight: 400; }
.bt-input-field-unit__right--disabled .bt-input-field-unit__field { color: var(--text-disabled); cursor: not-allowed; }

/* ── Clear button — v-if + <Transition name="bt-input-clear"> ─────── */
.bt-input-field-unit__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}
.bt-input-field-unit__clear svg,
.bt-input-field-unit__clear img { width: 16px; height: 16px; display: block; }

/* ── Unit dropdown ──────────────────────────────────────────────────── */
.bt-input-field-unit__dropdown {
  position: absolute;
  top: calc(100% + 4px);
  inset-inline-start: 0;
  min-width: 120px;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
  z-index: 100;
  overflow: hidden;
}
.bt-input-field-unit__dropdown-search {
  width: 100%;
  padding: 8px 12px;
  border: none;
  border-bottom: 1px solid var(--border-primary);
  outline: none;
  font-family: inherit;
  font-size: 13px;
  color: var(--text-primary);
  background: transparent;
  box-sizing: border-box;
}
.bt-input-field-unit__dropdown-search::placeholder { color: var(--text-secondary); }
.bt-input-field-unit__dropdown-item {
  padding: 10px 12px;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  cursor: pointer;
  transition: background 100ms;
}
.bt-input-field-unit__dropdown-item:hover { background: var(--bg-subtle); }
.bt-input-field-unit__dropdown-item--selected {
  color: var(--color-brand-primary);
  font-weight: 600;
  background: var(--color-brand-primary-subtle);
}
.bt-input-field-unit__dropdown-item--selected:hover {
  background: var(--color-brand-primary-subtle);
}
.bt-input-field-unit__dropdown-empty {
  padding: 16px 12px;
  font-size: 13px;
  color: var(--text-secondary);
  text-align: center;
}

/* ── Helper / error text ────────────────────────────────────────────── */
.bt-input-field-unit__helper { margin-top: 4px; padding: 0 4px; font-size: var(--typography-font-size-xs); font-weight: 500; }
.bt-input-field-unit__helper-text { color: var(--text-secondary); }
.bt-input-field-unit__helper-text--error { color: var(--text-error); }
.bt-input-field-unit__required { color: var(--text-error); margin-inline-start: var(--space-2xs); }

/* ── RTL: cursor/caret at inline-start (right in RTL) ──────────────────── */
[dir="rtl"] .bt-input-field-unit__field { direction: rtl; }

/**
 * BTInputFieldUnit — Split input: unit selector (left) + text field (right).
 * Each panel has its own independent border that activates separately:
 * left border activates when the dropdown opens, right when the field is focused.
 *
 * Sliced from Figma node 702-3937.
 *
 * ## Usage:
 * ```tsx
 * <BTInputFieldUnit
 *   units={[{ label: 'IDR', value: 'IDR' }, { label: 'USD', value: 'USD' }]}
 *   unitLabel="Currency"
 *   label="Amount"
 *   value={amount}
 *   onChange={setAmount}
 *   formatter={(v, u) => u?.value === 'IDR' ? formatRupiah(v) : v}
 *   sanitizer={(v) => v.replace(/\D/g, '')}
 *   onUnitChanged={handleUnitChange}
 * />
 * ```
 */
import * as React from 'react';
import './BTInputFieldUnit.css';
import type {
  BTInputFieldUnitHandle,
  BTInputFieldUnitProps,
  BTInputFieldUnitOption,
} from './BTInputFieldUnit.types';
import { useBTForm } from '../form/BTFormContext';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export const BTInputFieldUnit = React.forwardRef<BTInputFieldUnitHandle, BTInputFieldUnitProps>(
  function BTInputFieldUnit(
    {
      name,
      units,
      selectedUnit,
      initialUnit,
      unitLabel,
      hasSearch = false,
      itemsFilter,
      onUnitChanged,
      label,
      value,
      onChange,
      formatter,
      sanitizer,
      keyboardType = 'text',
      hintText,
      clearable = true,
      validator,
      errorText,
      helperText,
      disabled = false,
      required = false,
      className,
    },
    ref,
  ) {
    // ── State ───────────────────────────────────────────────────────────────
    const [isDropdownOpen, setIsDropdownOpen] = React.useState(false);
    const [isFieldFocused, setIsFieldFocused] = React.useState(false);
    const [internalUnit, setInternalUnit] = React.useState<BTInputFieldUnitOption | undefined>(
      initialUnit ?? units[0],
    );
    const [errorInternal, setErrorInternal] = React.useState<string | null>(null);
    const [searchQuery, setSearchQuery] = React.useState('');

    const rootRef  = React.useRef<HTMLDivElement>(null);
    const fieldRef = React.useRef<HTMLInputElement>(null);

    // ── BTForm wrapping (optional) ─────────────────────────────────────────
    const form = useBTForm();
    const isInForm = form !== null && typeof name === 'string';
    const formValue = isInForm ? (form.values[name] as string | undefined) : undefined;
    const formError = isInForm ? form.errorFor(name) : null;
    const resolvedValue = value ?? formValue;

    // ── Derived ─────────────────────────────────────────────────────────────
    const currentUnit = selectedUnit !== undefined ? selectedUnit : internalUnit;
    const activeError = errorText ?? errorInternal ?? formError ?? null;
    const hasError    = !!activeError;
    const resolvedRequired = required;
    const uid = React.useId();
    const fieldId = `bt-input-field-unit-${uid}`;
    const showClear   = clearable && !!resolvedValue && isFieldFocused && !disabled;
    const fieldLabelFloating = !!label && (isFieldFocused || !!resolvedValue);

    // ── Click-outside to close dropdown ────────────────────────────────────
    React.useEffect(() => {
      function onClickOutside(e: MouseEvent) {
        if (rootRef.current && !rootRef.current.contains(e.target as Node)) {
          setIsDropdownOpen(false);
        }
      }
      document.addEventListener('mousedown', onClickOutside);
      return () => document.removeEventListener('mousedown', onClickOutside);
    }, []);

    // ── Display value (formatted) ───────────────────────────────────────────
    const displayValue = React.useMemo(() => {
      const raw = resolvedValue ?? '';
      if (formatter && raw !== '') return formatter(raw, currentUnit ?? null);
      return raw;
    }, [resolvedValue, formatter, currentUnit]);

    // ── Filtered units for search ────────────────────────────────────────────
    const filteredUnits = React.useMemo(() => {
      if (!hasSearch || !searchQuery) return units;
      if (itemsFilter) return itemsFilter(units, searchQuery);
      const q = searchQuery.toLowerCase();
      return units.filter((u) => u.label.toLowerCase().includes(q));
    }, [units, hasSearch, searchQuery, itemsFilter]);

    // ── Input type / inputMode ───────────────────────────────────────────────
    const inputType = keyboardType === 'tel' ? 'tel' : 'text';
    const inputMode: React.HTMLAttributes<HTMLInputElement>['inputMode'] =
      keyboardType === 'number'  ? 'numeric'
      : keyboardType === 'decimal' ? 'decimal'
      : keyboardType === 'tel'     ? 'tel'
      : keyboardType === 'url'     ? 'url'
      : undefined;

    // ── Handlers ─────────────────────────────────────────────────────────────
    function toggleDropdown() {
      if (disabled) return;
      if (!isDropdownOpen) setSearchQuery('');
      setIsDropdownOpen((open) => !open);
    }

    function selectUnit(option: BTInputFieldUnitOption) {
      setInternalUnit(option);
      onUnitChanged?.(option);
      setIsDropdownOpen(false);
    }

    function handleFieldInput(e: React.ChangeEvent<HTMLInputElement>) {
      const raw = e.target.value;
      const sanitized = sanitizer ? sanitizer(raw, currentUnit ?? null) : raw;
      onChange?.(sanitized);
      if (isInForm) form.setField(name, sanitized);
    }

    function handleFieldBlur() {
      setIsFieldFocused(false);
      if (isInForm) form.touch(name);
    }

    function handleClear() {
      onChange?.('');
      if (isInForm) form.setField(name, '');
      setErrorInternal(null);
      fieldRef.current?.focus();
    }

    function validate(): boolean {
      if (!validator) return true;
      const result = validator(resolvedValue ?? '', currentUnit ?? null);
      setErrorInternal(result ?? null);
      return result === null;
    }

    React.useImperativeHandle(ref, () => ({ validate }), [resolvedValue, currentUnit, validator]);

    // ── CSS classes ──────────────────────────────────────────────────────────
    const leftClass = cn(
      'bt-input-field-unit__left',
      isDropdownOpen && 'bt-input-field-unit__left--active',
      hasError && 'bt-input-field-unit__left--error',
      disabled && 'bt-input-field-unit__left--disabled',
    );


    const rightClass = cn(
      'bt-input-field-unit__right',
      isFieldFocused && 'bt-input-field-unit__right--active',
      hasError && 'bt-input-field-unit__right--error',
      disabled && 'bt-input-field-unit__right--disabled',
    );

    return (
      <div ref={rootRef} className={cn('bt-input-field-unit__wrapper', className)}>
        <div className="bt-input-field-unit__row">

          {/* ── Left panel: unit selector ── */}
          <div
            className={leftClass}
            role="button"
            aria-expanded={isDropdownOpen}
            tabIndex={disabled ? -1 : 0}
            onClick={toggleDropdown}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleDropdown(); }
              if (e.key === 'Escape') setIsDropdownOpen(false);
            }}
          >
            {unitLabel && (
              <span className="bt-input-field-unit__unit-label">
                {unitLabel}
                {required && <span className="bt-input-field-unit__required">*</span>}
              </span>
            )}
            <div className="bt-input-field-unit__unit-row">
              <span className="bt-input-field-unit__unit-value">
                {currentUnit?.label ?? '—'}
              </span>
              <button
                type="button"
                className={cn(
                  'bt-input-field-unit__unit-chevron',
                  isDropdownOpen && 'bt-input-field-unit__unit-chevron--open',
                )}
                disabled={disabled}
                aria-label={isDropdownOpen ? 'Close unit selector' : 'Open unit selector'}
                tabIndex={-1}
                onClick={(e) => { e.stopPropagation(); toggleDropdown(); }}
              >
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                  <path d="M7 10l5 5 5-5z" />
                </svg>
              </button>
            </div>

            {/* Dropdown list */}
            {isDropdownOpen && (
              <div className="bt-input-field-unit__dropdown" role="listbox">
                {hasSearch && (
                  <input
                    className="bt-input-field-unit__dropdown-search"
                    type="text"
                    placeholder="Search..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    onMouseDown={(e) => e.stopPropagation()}
                    onClick={(e) => e.stopPropagation()}
                    onKeyDown={(e) => {
                      if (e.key === 'Escape') { e.stopPropagation(); setIsDropdownOpen(false); }
                    }}
                  />
                )}
                {filteredUnits.length > 0 ? (
                  filteredUnits.map((option) => (
                    <div
                      key={option.value}
                      className={cn(
                        'bt-input-field-unit__dropdown-item',
                        currentUnit?.value === option.value &&
                          'bt-input-field-unit__dropdown-item--selected',
                      )}
                      role="option"
                      aria-selected={currentUnit?.value === option.value}
                      onMouseDown={(e) => { e.preventDefault(); selectUnit(option); }}
                    >
                      {option.label}
                    </div>
                  ))
                ) : (
                  <div className="bt-input-field-unit__dropdown-empty">No result found.</div>
                )}
              </div>
            )}
          </div>

          {/* ── Divider ── */}

          {/* ── Right panel: text field ── */}
          <div className={rightClass}>
            {label && (
              <label
                className={cn(
                  'bt-input-field-unit__field-label',
                  fieldLabelFloating && 'bt-input-field-unit__field-label--floating',
                )}
              >
                {label}
                {required && <span className="bt-input-field-unit__required">*</span>}
              </label>
            )}
            <div className="bt-input-field-unit__right-inner">
              <input
                ref={fieldRef}
                id={fieldId}
                name={name}
                className={cn(
                  'bt-input-field-unit__field',
                  !!label && 'bt-input-field-unit__field--has-label',
                )}
                type={inputType}
                inputMode={inputMode}
                value={displayValue}
                placeholder={fieldLabelFloating || !label ? (hintText ?? '') : ''}
                disabled={disabled}
                aria-invalid={hasError || undefined}
                aria-required={resolvedRequired || undefined}
                onChange={handleFieldInput}
                onFocus={() => setIsFieldFocused(true)}
                onBlur={handleFieldBlur}
              />
              {showClear && (
                <button
                  type="button"
                  className="bt-input-field-unit__clear"
                  aria-label="Clear value"
                  tabIndex={-1}
                  onMouseDown={(e) => { e.preventDefault(); handleClear(); }}
                >
                  {/* Material cancel filled (circle with ×) */}
                  <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" fill="currentColor">
                    <path d="M12 2C6.47 2 2 6.47 2 12s4.47 10 10 10 10-4.47 10-10S17.53 2 12 2zm5 13.59L15.59 17 12 13.41 8.41 17 7 15.59 10.59 12 7 8.41 8.41 7 12 10.59 15.59 7 17 8.41 13.41 12 17 15.59z" />
                  </svg>
                </button>
              )}
            </div>
          </div>

        </div>

        {(activeError || helperText) && (
          <div className="bt-input-field-unit__helper">
            <span
              className={cn(
                'bt-input-field-unit__helper-text',
                hasError && 'bt-input-field-unit__helper-text--error',
              )}
              role={hasError ? 'alert' : undefined}
            >
              {activeError || helperText}
            </span>
          </div>
        )}
      </div>
    );
  },
);

BTInputFieldUnit.displayName = 'BTInputFieldUnit';

export interface BTInputFieldUnitHandle {
  validate: () => boolean;
}

export interface BTInputFieldUnitOption {
  /** Display text shown in dropdown (e.g. "IDR", "https://") */
  label: string;
  /** Unique identifier (e.g. "IDR", "+62") */
  value: string;
}

export interface BTInputFieldUnitProps {
  /** Field `name` — wires this input to BTForm context when wrapped. */
  name?: string;

  // ── Left dropdown ────────────────────────────────────────────────────────
  /** Available unit options for the left selector panel. Required. */
  units: BTInputFieldUnitOption[];
  /** Controlled selected unit. When provided, overrides internal selection. */
  selectedUnit?: BTInputFieldUnitOption;
  /** Initial unit in uncontrolled mode. Defaults to units[0]. */
  initialUnit?: BTInputFieldUnitOption;
  /** Floating label shown above the selected unit text (e.g. "Currency"). */
  unitLabel?: string;
  /** Show a search input at the top of the unit dropdown. @default false */
  hasSearch?: boolean;
  /**
   * Custom filter applied when hasSearch is true.
   * Defaults to case-insensitive label.contains(query).
   */
  itemsFilter?: (items: BTInputFieldUnitOption[], query: string) => BTInputFieldUnitOption[];
  /** Called when a unit option is selected. */
  onUnitChanged?: (unit: BTInputFieldUnitOption) => void;

  // ── Right text field ─────────────────────────────────────────────────────
  /** Floating label for the right text field (e.g. "Amount"). */
  label?: string;
  /** Controlled value — always the sanitized raw value. */
  value?: string;
  /** Called when the text value changes. */
  onChange?: (value: string) => void;
  /**
   * Display transformer: receives the raw value and current unit; returns
   * the string to show in the <input>. Does NOT affect the emitted value.
   */
  formatter?: (value: string, unit: BTInputFieldUnitOption | null) => string;
  /**
   * Input transformer: called on every input event; returns the raw value
   * to emit. Use to strip formatting characters. Defaults to identity.
   */
  sanitizer?: (value: string, unit: BTInputFieldUnitOption | null) => string;
  /** HTML input keyboard hint. @default 'text' */
  keyboardType?: 'text' | 'number' | 'decimal' | 'tel' | 'url';
  /** Placeholder shown in the right field when empty. */
  hintText?: string;
  /**
   * Show a × clear button when the right field has content and is focused.
   * @default true
   */
  clearable?: boolean;

  // ── Shared ───────────────────────────────────────────────────────────────
  /**
   * Validation function called by the exposed `validate()` method.
   * Return a non-null string for an error, or null to clear.
   */
  validator?: (value: string, unit: BTInputFieldUnitOption | null) => string | null;
  /** External error message (takes precedence over the internal validator). */
  errorText?: string;
  /** Helper text shown below when no error. */
  helperText?: string;
  /** @default false */
  disabled?: boolean;
  /** Appends " *" (red) to both labels. @default false */
  required?: boolean;
  className?: string;
}
